python3 -c "
import sys, json, os

tool_input = os.environ.get('TOOL_INPUT', '{}')
try:
    data = json.loads(tool_input)
except Exception:
    sys.exit(0)

file_path = data.get('file_path', '') or ''

# Only validate artifact JSON files
if '/knowledge/artifact/' not in file_path or not file_path.endswith('.json'):
    sys.exit(0)

# Extract doc type from filename prefix
import re
basename = os.path.basename(file_path)
match = re.match(r'^([A-Z]+)-', basename)
if not match:
    sys.exit(0)

doc_type = match.group(1)
base_dir = os.path.realpath('.')

import subprocess
result = subprocess.run(
    ['python3', 'knowledge/sdlc_chain/cli.py', 'validate', doc_type, file_path],
    capture_output=True, text=True, cwd=base_dir, timeout=15
)

if result.returncode != 0:
    print('Validation error: ' + result.stderr.strip(), file=sys.stderr)
else:
    try:
        out = json.loads(result.stdout)
        if out.get('status') == 'invalid':
            errors = out.get('errors', [])
            print('VALIDATION FAILED for ' + doc_type + ':', file=sys.stderr)
            for e in errors:
                print('  - ' + e, file=sys.stderr)
        elif out.get('warnings'):
            for w in out.get('warnings', []):
                print('  warning: ' + w, file=sys.stderr)
    except Exception:
        pass

sys.exit(0)
"
